DROP TABLE IF EXISTS `discussion_points`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `discussion_points` (
  `id` int NOT NULL AUTO_INCREMENT,
  `meeting_id` varchar(50) NOT NULL,
  `week_key` date NOT NULL,
  `question` text NOT NULL,
  `answer` text,
  `sort_order` int NOT NULL DEFAULT '0',
  `section_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_dp_meeting_week` (`meeting_id`,`week_key`),
  KEY `discussion_points_section_id_index` (`section_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2242 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
