--
-- Table structure for table `meta_ad_reports`
--

DROP TABLE IF EXISTS `meta_ad_reports`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `meta_ad_reports` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `project` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'hima',
  `campaign_name` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `ad_set_name` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `ad_name` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `reach` bigint NOT NULL DEFAULT '0',
  `impressions` bigint NOT NULL DEFAULT '0',
  `frequency` decimal(12,8) NOT NULL DEFAULT '0.00000000',
  `result_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `results` int NOT NULL DEFAULT '0',
  `amount_spent` decimal(12,2) NOT NULL DEFAULT '0.00',
  `cost_per_result` decimal(12,8) DEFAULT NULL,
  `cpc` decimal(12,8) DEFAULT NULL,
  `cpm` decimal(12,8) DEFAULT NULL,
  `ctr` decimal(12,8) DEFAULT NULL,
  `app_installs` int NOT NULL DEFAULT '0',
  `cost_per_install` decimal(12,8) DEFAULT NULL,
  `new_user_first_purchase` int NOT NULL DEFAULT '0',
  `cost_per_first_purchase` decimal(12,8) DEFAULT NULL,
  `reporting_starts` date NOT NULL,
  `reporting_ends` date NOT NULL,
  `uploaded_by` int NOT NULL,
  `source_file` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `row_hash` char(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `meta_ad_reports_unique_row` (`row_hash`),
  KEY `meta_ad_reports_reporting_starts_index` (`reporting_starts`),
  KEY `meta_ad_reports_reporting_ends_index` (`reporting_ends`),
  KEY `meta_ad_reports_uploaded_by_index` (`uploaded_by`),
  KEY `meta_ad_reports_project_index` (`project`),
  CONSTRAINT `meta_ad_reports_uploaded_by_foreign` FOREIGN KEY (`uploaded_by`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1163 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

