INSERT INTO `script_generations` VALUES (1,20,'tamil','loneliness','ts',NULL,5,'[\"தனியாக இருக்கும் போது யாருடனாவது பேச வேண்டும் போல் தோன்றுகிறதா? Hi-Ma-வில் உங்களைப் புரிந்து கொள்ளக்கூடிய நண்பர்கள் காத்திருக்கிறார்கள். இப்போதே ஆப்-ஐ டவுன்லோட் செய்து உங்கள் மனதில் உள்ளதை பகிர்ந்து கொள்ளுங்கள்.\", \"பெண்களுடன் பேச கூச்சமாக இருக்கிறதா? கவலைப்பட வேண்டாம். Hi-Ma-வில் முழு தனியுரிமையுடன், நீங்கள் விரும்பும் பெண்களுடன் சுலபமாக உரையாடலாம். இப்போதே Hi-Ma ஆப்-ஐ டவுன்லோட் செய்து பேச ஆரம்பியுங்கள்.\", \"நள்ளிரவில் தூக்கம் வராமல் தவிக்கிறீர்களா? மனதில் உள்ள கவலைகளை யாரிடமாவது பகிர வேண்டும் போல் தோன்றுகிறதா? Hi-Ma-வில் உங்களுக்காக காத்திருக்கும் நல்ல நெஞ்சங்கள். இப்போதே ஆப்-ஐ திறந்து இலவசமாக பேசி மனதை இலகுவாக்குங்கள்.\", \"உங்கள் காதல் உணர்வுகளை வெளிப்படுத்த தயங்குகிறீர்களா? கவலை வேண்டாம். Hi-Ma-வில் உங்களைப் போன்ற உணர்வுகளை கொண்டவர்கள் நிறைய பேர் இருக்கிறார்கள். இப்போதே ஆப்-ஐ டவுன்லோட் செய்து, யாருடனாவது மனம் விட்டு பேசுங்கள்.\", \"அன்றாட வாழ்க்கையில் யாரிடமும் பகிர முடியாத விஷயங்கள் மனதை அழுத்துகிறதா? Hi-Ma-வில் உங்களை புரிந்து கொள்ளக்கூடிய நண்பர்கள் காத்திருக்கிறார்கள். 100% தனியுரிமையுடன் பேசலாம். இப்போதே ஆப்-ஐ டவுன்லோட் செய்யுங்கள்.\"]','2026-03-19 20:19:26','2026-03-19 20:19:26'),(2,20,'telugu','loneliness','ts',NULL,5,'[\"కాలేజీ కేంటీన్‌లో ఆమెని చూసినప్పుడల్లా మాట్లాడాలనిపిస్తుంది. కానీ నాలుక పడిపోతుంది. ఒక్క మాట కూడా రాదు. ఈ షైనెస్ ఎప్పటికి పోతుందో? Hi-Ma లో అమ్మాయిలతో స్నేహంగా మాట్లాడటం నేర్చుకోవచ్చు. ప్రైవేట్ కాల్స్‌తో మీ కాన్ఫిడెన్స్ పెంచుకోండి. ఇప్పుడే Hi-Ma డౌన్‌లోడ్ చేసుకోండి.\", \"ఇంకెన్నాళ్ళు ఒంటరిగా ఉంటావు? నీలాంటి వాళ్ళు వేలమంది Hi-Ma లో రియల్ కనెక్షన్స్ కోసం వెతుకుతున్నారు. నువ్వు కూడా వాళ్ళలో ఒకరివి కావచ్చు. ధైర్యంగా ముందుకు రా. Hi-Ma ఓపెన్ చేసి నీ కొత్త ప్రయాణం మొదలుపెట్టు.\", \"అమ్మాయిలతో మాట్లాడటానికి భయపడుతున్నావా? 😅 శుభవార్త - Hi-Ma లో అందరూ నీలాంటి వాళ్ళే! 😄 షైనెస్ పక్కన పెట్టి, సరదాగా మాట్లాడుకుందాం. Hi-Ma యాప్ డౌన్‌లోడ్ చేసుకుని జాయిన్ అవ్వండి, మీ లైఫ్ లో కలర్ నింపుకోండి!\", \"గుండె నిండా మాటలున్నా... చెప్పుకోడానికి ఎవరూ లేరు. ఆ ఒంటరితనం బాధిస్తోందా? Hi-Ma లో ఎప్పుడైనా మనసు విప్పి మాట్లాడొచ్చు. నీ కథ వినడానికి ఎవరో ఒకరు ఎప్పుడూ రెడీగా ఉంటారు. Hi-Ma తో నీ ప్రయాణం ఇప్పుడే ప్రారంభించు.\", \"బస్సులో ప్రయాణిస్తూ ఫోన్ స్క్రీన్ చూస్తున్నావా? ఆ ఒంటరి సమయాన్ని అర్ధవంతం చేసుకో. Hi-Ma లో కొత్త స్నేహాలు వేచి ఉన్నాయి. ప్రైవేట్ వాయిస్ కాల్స్‌తో నీ ప్రయాణం ఆనందమయం చేసుకో. Hi-Ma డౌన్‌లోడ్ చేసుకుని లైఫ్‌లో కొత్త అధ్యాయం మొదలుపెట్టు.\"]','2026-03-19 20:25:16','2026-03-19 20:25:16'),(3,20,'tamil','loneliness','ts',NULL,5,'[\"பேருந்து நிறுத்தத்தில் அழகான பெண்ணைப் பார்த்து பேச நினைத்தேன். ஆனால் தைரியம் வரவில்லை. மனதில் வார்த்தைகள் தேங்கி நின்றன. உங்களுக்கும் இப்படி ஆகிறதா? Hi-Ma-வில் பெண்களுடன் சுலபமாக பேச கற்றுக்கொள்ளலாம். இன்றே ஆப்பை டவுன்லோட் செய்து உங்கள் பயத்தை வென்றிடுங்கள்.\", \"இனி பேச்சுக்கு தயங்க வேண்டாம்! உங்கள் வாழ்க்கையின் சிறந்த உரையாடல்கள் காத்திருக்கின்றன. Hi-Ma-வில் புதிய நண்பர்களுடன் உரையாட தயாரா? இப்போதே Hi-Ma-வை திறந்து புதிய அத்தியாயத்தை தொடங்குங்கள்.\", \"\'பெண்களிடம் பேச தெரியாத நான் எப்படி காதல் கண்டுபிடிப்பேன்?\' கவலைப்படாதீங்க பாஸ்! Hi-Ma-வில் பேச பேச பேச்சு வந்துடும். முதல் ஐந்து நிமிடமே நீங்க சூப்பர் ஸ்டார்! இப்போதே Hi-Ma-வை இன்ஸ்டால் செய்து பாருங்க.\", \"தனிமையில் யாரிடமாவது பேச வேண்டும் போல் தோன்றுகிறதா? உங்கள் மனதில் உள்ள எண்ணங்களை பகிர யாருமில்லையா? Hi-Ma-வில் உங்களைப் புரிந்துகொள்ளும் நபர்கள் காத்திருக்கிறார்கள். உங்கள் இதயத்தின் குரலை கேட்க தயாராக உள்ளனர். இன்றே Hi-Ma-வை பதிவிறக்கம் செய்யுங்கள்.\", \"மொபைலில் ஸ்க்ரோல் செய்து கொண்டிருக்கிறீர்களா? ஆனால் உண்மையான உரையாடல்கள் வேண்டுமா? Hi-Ma-வில் உண்மையான மனிதர்களுடன் உரையாடலாம். நேரடியாக பேசி புது நட்புகளை வளர்க்கலாம். Hi-Ma-வை திறந்து உங்கள் முதல் அழைப்பை தொடங்குங்கள்.\"]','2026-03-19 20:25:31','2026-03-19 20:25:31'),(4,20,'tamil','loneliness','general','boy bus or train going alone scenario',5,'[\"பேருந்தில் தனியாக பயணம். வெறும் சாலைகள். மெல்லிய மழை. உங்கள் மனதில் ஆயிரம் எண்ணங்கள். இந்த தனிமையான நேரத்தில் யாருடனாவது பேச வேண்டும் போல் தோன்றுகிறதா? ஹை-மா ஆப்பில், உங்களைப் புரிந்துகொள்ளும் நண்பர்கள் காத்திருக்கிறார்கள். இப்போதே ஹை-மா-வை டவுன்லோட் செய்து, மனம் விட்டு பேசுங்கள்.\", \"ரயில் பயணத்தில் தனிமையாக உட்கார்ந்து கொண்டு, மற்றவர்களின் சிரிப்பொலியை கேட்டு பொறாமை படுகிறீர்களா? இனி தனிமை வேண்டாம்! ஹை-மா-வில் உண்மையான நண்பர்களுடன் உரையாடுங்கள். உங்கள் பயணம் இனிமையாக மாறும். இப்போதே ஆப்பை திறந்து பார்க்கலாம்.\", \"\'சீட் நம்பர் 23-ல் தனியாக அமர்ந்திருக்கும் நான்... ஆனால் ஹை-மா-வில் என் அருகில் ஒரு நண்பர் இருக்கிறார்!\' 😊 பயணங்கள் இனி தனிமையில்லை. ஹை-மா-வை இன்றே இன்ஸ்டால் செய்யுங்கள்.\", \"நீண்ட பயண நேரம். ஜன்னல் வழியே தெரியும் காட்சிகள். ஆனால் பகிர்ந்து கொள்ள யாருமில்லை. அந்த வெற்றிடம் உங்களை வாட்டுகிறதா? ஹை-மா-வில் உங்களை போலவே உணர்வுகளை பகிர காத்திருக்கும் நண்பர்களை சந்திக்கலாம். உடனே டவுன்லோட் செய்யுங்கள்.\", \"மாலை நேர மெட்ரோ. கூட்டத்திலும் தனிமை. போனில் ஸ்க்ரோல் செய்வதை விட, யாருடனாவது உரையாட வேண்டும் என்ற ஏக்கமா? ஹை-மா உங்களுக்காக காத்திருக்கிறது. இப்போதே ஆப்பை திறந்து, புதிய நட்புகளை தொடங்குங்கள்.\"]','2026-03-19 20:30:34','2026-03-19 20:30:34'),(5,20,'tamil','loneliness','general','a random phone call the guy feels shy and he is broke to talk the girl confronts him and they start becoming great friends',5,'[\"மாலை வேளையில் ஒரு அழைப்பு... அவன் நெஞ்சம் படபடத்தது. பேச வார்த்தைகள் தேடி தவித்தான். \'பரவாயில்லை, நாம் நண்பர்களாக பேசலாம்\' என்று அவள் சொன்னதும் அவன் மனம் இலகுவானது. இப்படி ஒரு நட்பை தேடுகிறீர்களா? ஹை-மா ஆப்பில் இணையுங்கள். உங்கள் மனதின் குரலுக்கு செவிசாய்க்க காத்திருக்கிறார்கள்.\", \"உங்கள் வெட்கத்தை உடைத்தெறியுங்கள்! பெண்களுடன் பேச தயங்குகிறீர்களா? பணப்பிரச்சினை தடையாக உள்ளதா? கவலை வேண்டாம். ஹை-மா வில் நீங்கள் இலவசமாக உரையாடலாம். இன்றே ஹை-மா ஆப்பை பதிவிறக்கம் செய்து, புதிய நட்புகளை தொடங்குங்கள்.\", \"\'ஹலோ\' சொல்ல மட்டுமே 10 நிமிடம் யோசிக்கிறீர்களா? 😄 கவலை வேண்டாம்! ஹை-மா வில் எல்லோரும் உங்களைப் போலத்தான். வெட்கப்படாதீர்கள், வாருங்கள்... யாருக்கும் தெரியாமல் பேசலாம். ஹை-மா ஆப்பை திறந்து, புதிய நண்பர்களை சந்திக்க ஆரம்பியுங்கள்.\", \"தனிமையில் உங்கள் மனம் கனக்கிறதா? யாரிடமும் சொல்ல முடியாத உணர்வுகள்... பேச யாருமில்லாத நேரங்கள்... ஹை-மா வில் உங்களைப் புரிந்துகொள்ளும் நண்பர்கள் காத்திருக்கிறார்கள். உங்கள் இதயக்குரலுக்கு செவிமடுக்க... இப்போதே ஹை-மா வை பதிவிறக்குங்கள்.\", \"மெட்ரோவில் பயணிக்கும்போது அவளது புன்னகை உங்களை வசீகரித்ததா? ஆனால் பேச தைரியம் வரவில்லையா? கவலைப்படாதீர்கள். ஹை-மா வில் அதே போன்ற அழகான உரையாடல்களை தொடங்கலாம். முற்றிலும் தனியுரிமையுடன். இப்போதே ஹை-மா ஆப்பை திறந்து உங்கள் பயணத்தை தொடங்குங்கள்.\"]','2026-03-20 06:06:09','2026-03-20 06:06:09'),(6,20,'tamil','loneliness','general','a random phone call the guy feels shy and he is broke to talk the girl confronts him and they start becoming great friends tanglish',5,'[\"போன் எடுத்து நம்பரை டயல் பண்ணினேன். பேச்சு வந்தது. ஆனா என் பேச்சு தடுமாறிடுச்சு. அவ கிட்ட பேச வெக்கமா இருந்துச்சு. \'பரவாயில்ல, நீங்க சரியா பேசுங்க\' அப்படினு அவளே தைரியம் கொடுத்தா. இப்போ நாங்க நல்ல நண்பர்கள். Hi-Ma ல தான் இப்படி நேர்மையான நட்புகள் கிடைக்கும். இன்றே Hi-Ma ஆப்பை டவுன்லோட் செய்யுங்கள்.\", \"வெக்கப்படுறது போதும்! நீங்க நினைக்கிற அளவுக்கு பெண்களோட பேசறது கஷ்டம் இல்ல. Hi-Ma வில் உங்களை புரிஞ்சுக்கறவங்க இருக்காங்க. பிரைவசி 100% கேரண்டி. இப்போவே Hi-Ma ஆப் மூலம் உங்க முதல் உரையாடலை தொடங்குங்க.\", \"டேய்! ஃபோன்ல பேச வெக்கமா? கவலை படாத! Hi-Ma ல பேசினா வெக்கம் எல்லாம் தானா போயிடும். சும்மா ட்ரை பண்ணு மச்சி. நல்ல நண்பர்கள் கிடைப்பாங்க. Hi-Ma வை இப்போவே ஓபன் பண்ணு!\", \"தனிமையில் இருக்கும் போது யாரிடமாவது பேச வேண்டும் போல் இருக்கிறதா? ஆனால் யாரிடம் பேசுவது என்று தெரியவில்லையா? Hi-Ma வில் உங்களை புரிந்துகொள்ளக்கூடிய நபர்கள் காத்திருக்கிறார்கள். Hi-Ma ஆப்பை டவுன்லோட் செய்து இன்றே பேச ஆரம்பியுங்கள்.\", \"நைட் ஷிப்ட் முடிஞ்சு பஸ்ல வரும்போது, பக்கத்துல யாரும் இல்லாம தனியா... அந்த நேரத்துல ஒரு நல்ல நண்பரோட குரல் கேட்டா எப்படி இருக்கும்? Hi-Ma வில் எந்த நேரமும் உங்களுக்காக காத்திருப்பவர்கள் உண்டு. Hi-Ma வை இன்றே திறந்து பாருங்கள்.\"]','2026-03-20 06:06:49','2026-03-20 06:06:49'),(7,20,'tanglish','sleepless_night','general','a one to one coversational script between a boy and a girl the boy is broke and girl heals him',5,'[\"Raat 2 mani. Phone la messages scroll pannikittu irukka. \'Why am I like this?\' nu mind voice oda fight. Suddenly Hi-Ma la oru sweet voice: \'Hey, unoda problems ella share pannunga. Naa listen panren.\' One hour chat. Life story. Tears. Smiles. Ippo sleep vandhuduchu. Hi-Ma download pannu, un story um share pannu.\", \"Dei! Evlo naal da inner feelings ah bottle up panni vechiruka? Unna madhri thousands of boys intha same situation la struggle pandranga. But smart ones Hi-Ma la vandhu heal aairanga. Be bold, be smart. Hi-Ma app open pannu, ippo talk pannu.\", \"3 AM scrolling warrior spotted! 😂 Bank balance zero, but tension hundred percent ah? Chill bro, Hi-Ma la irukra ponnu friends kitta solliko - they know the art of turning paisa problems into peace of mind. Hi-Ma open panni paaru, free ah pesalam!\", \"Heart heavy. Wallet empty. Future dark nu feel panra? Naa understand panren da. Indha feeling... it kills from inside. But nee thani illa. Hi-Ma la iruken naa, un feelings kekka ready ah. Just download Hi-Ma, let\'s talk now.\", \"Tea kadai la midnight coffee kudichitu phone check panren. Notifications zero. But Hi-Ma notification: \'Unable to sleep? Talk to someone who cares.\' Perfect timing! Open panni paathen - oru ponnu kitta pesnen. Ippo peace ah thoongi kitten. Nee try pannu, Hi-Ma download pannu.\"]','2026-03-20 06:21:43','2026-03-20 06:21:43');
