CREATE TABLE `script_library_items` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `script_generation_id` bigint unsigned DEFAULT NULL,
  `body` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `language` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `topic` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `script_library_items_user_id_foreign` (`user_id`),
  KEY `script_library_items_script_generation_id_foreign` (`script_generation_id`),
  CONSTRAINT `script_library_items_script_generation_id_foreign` FOREIGN KEY (`script_generation_id`) REFERENCES `script_generations` (`id`) ON DELETE SET NULL,
  CONSTRAINT `script_library_items_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
