DROP TABLE IF EXISTS `tessa_tasks`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tessa_tasks` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `assigned_by` int NOT NULL,
  `assigned_to` int NOT NULL,
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `priority` enum('low','medium','high','urgent') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'medium',
  `status` enum('pending','in_progress','completed','cancelled','on_hold') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `deadline` timestamp NULL DEFAULT NULL,
  `reminded_at` timestamp NULL DEFAULT NULL,
  `remind_count` int unsigned NOT NULL DEFAULT '0',
  `status_note` text COLLATE utf8mb4_unicode_ci,
  `ai_summary` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `blocker_status` enum('on_track','blocked','no_update','at_risk') COLLATE utf8mb4_unicode_ci DEFAULT 'no_update',
  `blocker_note` text COLLATE utf8mb4_unicode_ci,
  `progress` tinyint unsigned NOT NULL DEFAULT '0',
  `last_checkin_at` timestamp NULL DEFAULT NULL,
  `next_checkin_at` timestamp NULL DEFAULT NULL,
  `completed_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `tessa_tasks_assigned_to_status_index` (`assigned_to`,`status`),
  KEY `tessa_tasks_assigned_by_status_index` (`assigned_by`,`status`),
  CONSTRAINT `tessa_tasks_assigned_by_foreign` FOREIGN KEY (`assigned_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `tessa_tasks_assigned_to_foreign` FOREIGN KEY (`assigned_to`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `tessa_tasks`
--

LOCK TABLES `tessa_tasks` WRITE;
/*!40000 ALTER TABLE `tessa_tasks` DISABLE KEYS */;
/*!40000 ALTER TABLE `tessa_tasks` ENABLE KEYS */;
