INSERT INTO `tickets` VALUES (1,'test','tess','ai','high','closed',1,41,'2026-03-24 16:19:53','2026-03-24 10:49:44','2026-03-24 10:49:54'),(2,'test','test','ai','medium','closed',1,41,NULL,'2026-03-24 10:51:00','2026-03-24 12:16:26'),(3,'ugjg',NULL,'ai','high','closed',5,41,NULL,'2026-03-24 10:53:16','2026-03-24 12:16:31'),(4,'AI tickets','People raise more than 5 tickets, but not redirected to manual team.\n\nFirst all ticket will take AI take and then if the ticket is manually issue means (ex: \n1.Call amount not added\n2.dual time coins deduction\n3. recharge sucessfully but coins not added\n4. blocking related issue ) this type of tickets will be diretirect to staffs','ai','high','resolved',2,41,'2026-03-27 10:50:43','2026-03-24 12:21:48','2026-03-27 05:20:43'),(5,'AI poster generation','Currently all languages poster is data mis match that concern language staff told \nneed to fix also improve the poster design some posters design is not good ( example : Font is not visble , color )','ai','high','resolved',2,41,'2026-03-27 10:50:50','2026-03-24 12:24:17','2026-03-27 05:20:50'),(6,'Smart Notifications','Notifications are currently not being generated properly in regional languages, and users are receiving old and repetitive notifications. This needs to be improved.\n\nOn the user side, notifications should be more personalized and relevant to their activity, interests, and interactions. Similarly, on the creator side, notifications should focus on meaningful engagement, such as connection opportunities, user activity, and performance updates.\n\nOverall, the notification system needs improvement in terms of language support, freshness, personalization, and relevance to enhance user and creator engagement.','ai','high','resolved',2,41,'2026-03-27 10:50:58','2026-03-24 12:28:17','2026-03-27 05:20:58'),(7,'Auto-Moderation for Inappropriate Name and Description Content','If a female user enters inappropriate or abusive words in the Name or Description fields during registration, those words should be automatically replaced with proper and respectful words. The Name and Description should be changed to good and acceptable text.','ai','medium','open',2,41,NULL,'2026-03-27 08:15:54','2026-03-27 08:15:54'),(8,'Demo Video Section Showing Incorrect Content','In the app, the “Given Set of Category Wise” feature is not working as shown in the demo video. Instead, the demo video section is currently displaying a payment gateway video. Already mentioned queries in the meeting.','technical','high','in_progress',13,34,NULL,'2026-03-29 13:26:05','2026-03-30 10:02:40'),(9,'Users Still Seeing Demo Content After completing the 2 rupees payment','After completing the ₹2 payment, the app is still showing the payment demo video when clicking on thumbnails. Ideally, once the payment is successful, users should be able to view the full videos instead of the demo content. Please ensure proper access is provided after payment.','technical','high','in_progress',13,34,NULL,'2026-03-30 05:25:38','2026-03-30 10:02:37');
